// isPrivateIP checks if an IP address is private, loopback, or link-local.
func isPrivateIP(ip net.IP) bool {
	if ip.IsLoopback() || ip.IsLinkLocalUnicast() || ip.IsLinkLocalMulticast() {
		return true
	}
	// IsPrivate covers RFC 1918 (IPv4) and RFC 4193 (IPv6)
	return ip.IsPrivate()
}

// isSafeURL resolves the hostname and checks if it points to a restricted IP.
func isSafeURL(u *url.URL) error {
	host := u.Hostname()
	if host == "" {
		return fmt.Errorf("empty hostname")
	}

	// Check if host is an IP address directly
	ip := net.ParseIP(host)
	if ip != nil {
		if isPrivateIP(ip) {
			return fmt.Errorf("access to private IP addresses is not allowed")
		}
		return nil
	}

	// Resolve hostname to IPs
	ips, err := net.LookupIP(host)
	if err != nil {
		return fmt.Errorf("failed to resolve hostname: %v", err)
	}

	for _, resolvedIP := range ips {
		if isPrivateIP(resolvedIP) {
			return fmt.Errorf("access to private IP addresses is not allowed")
		}
	}

	return nil
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode {
