	if !strings.EqualFold(parsedURL.Scheme, "http") && !strings.EqualFold(parsedURL.Scheme, "https") {
		ctx.Error("Invalid URL scheme", fasthttp.StatusBadRequest)
		return
	}

	host := parsedURL.Hostname()
	if host == "" {
