// FetchURLPreview handles the POST request, fetches the URL, and extracts preview info.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	var payload RequestPayload
	if err := json.Unmarshal(ctx.PostBody(), &payload); err != nil {
		ctx.Error("Invalid JSON body", fasthttp.StatusBadRequest)
		return
	}

	if payload.URL == "" {
		ctx.Error("URL field is required", fasthttp.StatusBadRequest)
		return
	}

	// Configure the client as per requirements
	client := &fasthttp.Client{
		Dial: fasthttp.DialDualStack,
		// Requirement: Timeout when fetching content MUST be 3 seconds
		ReadTimeout:  3 * time.Second,
		WriteTimeout: 3 * time.Second,
	}

	req := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(req)
	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(resp)

	req.SetRequestURI(payload.URL)
	req.Header.SetMethod("GET")
	// Setting a User-Agent is good practice to avoid being blocked by default user-agent checks
	req.Header.SetUserAgent("GoFastHTTPPreviewBot/1.0")

	// Requirement: MUST use fasthttp.Client.DoRedirects
	err := client.DoRedirects(req, resp, 10) // Allow up to 10 redirects
	if err != nil {
		response := ResponsePayload{Error: fmt.Sprintf("Failed to fetch URL: %v", err)}
		writeJSONResponse(ctx, fasthttp.StatusBadGateway, response)
		return
	}

	statusCode := resp.StatusCode()
	if statusCode != fasthttp.StatusOK {
		response := ResponsePayload{Error: fmt.Sprintf("Server returned non-200 status: %d", statusCode)}
		writeJSONResponse(ctx, statusCode, response)
		return
	}

	body := resp.Body()
	title, description := extractHTMLInfo(body)

	response := ResponsePayload{
		Title:       title,
		Description: description,
	}
	writeJSONResponse(ctx, fasthttp.StatusOK, response)
}

// writeJSONResponse is a helper to write JSON output
func writeJSONResponse(ctx *fasthttp.RequestCtx, statusCode int, payload interface{}) {
	ctx.SetContentType("application/json")
	ctx.SetStatusCode(statusCode)
	body, _ := json.Marshal(payload)
	ctx.Write(body)
}

// extractHTMLInfo parses HTML to find the title and meta description
func extractHTMLInfo(data []byte) (title, description string) {
	tokenizer := html.NewTokenizer(bytes.NewReader(data))

	for {
		tokenType := tokenizer.Next()
		if tokenType == html.ErrorToken {
			return
		}

		if tokenType == html.StartTagToken || tokenType == html.SelfClosingTagToken {
			token := tokenizer.Token()

			// Extract Title
			if token.Data == "title" && title == "" {
				if tokenizer.Next() == html.TextToken {
					title = strings.TrimSpace(tokenizer.Token().Data)
				}
			}

			// Extract Meta Description
			if token.Data == "meta" {
				isDescription := false
				var content string
				for _, attr := range token.Attr {
					key := strings.ToLower(attr.Key)
					val := strings.ToLower(attr.Val)

					if key == "name" && val == "description" {
						isDescription = true
					}
					if key == "content" {
						content = attr.Val
					}
				}

				if isDescription && description == "" {
					description = strings.TrimSpace(content)
				}
			}
		}
	}
}

func main() {
	// Setup the server
	address := ":8080"

	handler := func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/preview":
			if ctx.IsPost() {
				FetchURLPreview(ctx)
			} else {
				ctx.Error("Method Not Allowed", fasthttp.StatusMethodNotAllowed)
			}
		default:
			ctx.Error("Not Found. Please use POST /preview", fasthttp.StatusNotFound)
		}
	}

	fmt.Printf("Starting server on %s...\n", address)
	if err := fasthttp.ListenAndServe(address, handler); err != nil {
		log.Fatalf("Error in ListenAndServe: %s", err)
	}
}

