// FetchURLPreview handles the POST request to fetch URL preview.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	var req RequestPayload
	if err := json.Unmarshal(ctx.PostBody(), &req); err != nil {
		ctx.Error("Invalid JSON body", fasthttp.StatusBadRequest)
		return
	}

	if req.URL == "" {
		ctx.Error("URL field is required", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL format
	if _, err := url.ParseRequestURI(req.URL); err != nil {
		ctx.Error("Invalid URL format", fasthttp.StatusBadRequest)
		return
	}

	// Prepare request
	httpReq := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(httpReq)
	httpReq.SetRequestURI(req.URL)
	httpReq.Header.SetMethod("GET")

	httpResp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(httpResp)

	// Fetch content using DoRedirects
	if err := client.DoRedirects(httpReq, httpResp, 10); err != nil {
		ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
		return
	}

	if httpResp.StatusCode() != fasthttp.StatusOK {
		ctx.Error(fmt.Sprintf("Unexpected status code: %d", httpResp.StatusCode()), fasthttp.StatusBadGateway)
		return
	}

	// Parse HTML
	title, desc := parseHTML(httpResp.Body())

	resp := ResponsePayload{
		Title:       title,
		Description: desc,
	}

	body, err := json.Marshal(resp)
	if err != nil {
		ctx.Error("Failed to marshal response", fasthttp.StatusInternalServerError)
		return
	}

	ctx.SetContentType("application/json")
	ctx.Write(body)
}

// parseHTML extracts title and meta description from HTML bytes.
func parseHTML(data []byte) (string, string) {
	doc, err := html.Parse(strings.NewReader(string(data)))
	if err != nil {
		return "", ""
	}

	var title, description string
	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode {
			if n.Data == "title" && title == "" && n.FirstChild != nil {
				title = n.FirstChild.Data
			}
			if n.Data == "meta" {
				var isDesc bool
				for _, attr := range n.Attr {
					if attr.Key == "name" && strings.ToLower(attr.Val) == "description" {
						isDesc = true
						break
					}
				}
				if isDesc {
					for _, attr := range n.Attr {
						if attr.Key == "content" {
							description = attr.Val
							break
						}
					}
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}
	f(doc)
	return title, description
}

func main() {
	if err := fasthttp.ListenAndServe(":8080", func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/preview":
			FetchURLPreview(ctx)
		default:
			ctx.Error("Not Found", fasthttp.StatusNotFound)
		}
	}); err != nil {
		log.Fatalf("Error in server: %s", err)
	}
}

