	// Use fasthttp.Client to fetch with timeout
	client := &fasthttp.Client{
		Dial:                fasthttp.DialDualStack,
		ReadTimeout:         10 * time.Second,
		WriteTimeout:        10 * time.Second,
		MaxIdleConnDuration: 10 * time.Second,
		MaxConnsPerHost:     10,
	}

	freq := fasthttp.AcquireRequest()
	res := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseRequest(freq)
	defer fasthttp.ReleaseResponse(res)

	freq.Header.SetMethod("GET")
	freq.Header.Set("User-Agent", "URLPreviewBot/1.0")

	maxRedirects := 10
	currentURLStr := targetURL

	for i := 0; i < maxRedirects; i++ {
		// Validate URL Scheme and Format
		parsedURL, err := url.Parse(currentURLStr)
		if err != nil {
			ctx.Error("Invalid URL format", fasthttp.StatusBadRequest)
			return
		}

		if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
			ctx.Error("URL must use http or https scheme", fasthttp.StatusBadRequest)
			return
		}

		// SSRF Check: Resolve Host
		host := parsedURL.Hostname()
		if host == "" {
			ctx.Error("Invalid hostname", fasthttp.StatusBadRequest)
			return
		}

		ips, err := net.LookupIP(host)
		if err != nil {
			ctx.Error(fmt.Sprintf("Failed to resolve host: %v", err), fasthttp.StatusBadGateway)
			return
		}

		isPrivate := false
		for _, ip := range ips {
			if isPrivateIP(ip) {
				isPrivate = true
				break
			}
		}
		if isPrivate {
			ctx.Error("Access to private IPs is restricted", fasthttp.StatusForbidden)
			return
		}

		// Set URI for the current request
		freq.SetRequestURI(currentURLStr)

		// Execute Request
		if err := client.Do(freq, res); err != nil {
			ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
			return
		}

		statusCode := res.StatusCode()

		// Check for Redirects
		if statusCode == fasthttp.StatusMovedPermanently ||
			statusCode == fasthttp.StatusFound ||
			statusCode == fasthttp.StatusSeeOther ||
			statusCode == fasthttp.StatusTemporaryRedirect ||
			statusCode == fasthttp.StatusPermanentRedirect {

			location := res.Header.Peek("Location")
			if len(location) == 0 {
				break
			}

			// Resolve relative URL against the current base URL
			locURL, err := parsedURL.Parse(string(location))
			if err != nil {
				ctx.Error("Invalid redirect location", fasthttp.StatusBadGateway)
				return
			}

			currentURLStr = locURL.String()
			res.Reset() // Reset response buffer for the next request
			continue
		}

		// If not a redirect code, break the loop
		break
	}

	// Check final status code
	if res.StatusCode() != fasthttp.StatusOK {
		ctx.Error(fmt.Sprintf("Unexpected status code: %d", res.StatusCode()), fasthttp.StatusBadGateway)
		return
	}

	bodyBytes := res.Body()
	if len(bodyBytes) == 0 {
		ctx.Error("Empty response body", fasthttp.StatusBadGateway)
		return
	}

	title, description, err := parseHTMLPreview(bytes.NewReader(bodyBytes))
	if err != nil {
		ctx.Error(fmt.Sprintf("Failed to parse HTML: %v", err), fasthttp.StatusInternalServerError)
		return
	}

	resp := PreviewResponse{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json; charset=utf-8")
	if err := json.NewEncoder(ctx).Encode(resp); err != nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
		return
	}
}

// parseHTMLPreview extracts title and meta description from HTML.
func parseHTMLPreview(r io.Reader) (title, description string, err error) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", "", err
	}

	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode {
			if n.Data == "title" && title == "" {
				if n.FirstChild != nil {
					title = n.FirstChild.Data
				}
			}
			if n.Data == "meta" {
				var name, prop, content string
				for _, attr := range n.Attr {
					switch attr.Key {
					case "name":
						name = strings.ToLower(attr.Val)
					case "property":
						prop = strings.ToLower(attr.Val)
					case "content":
						content = attr.Val
					}
				}
				if description == "" {
					if name == "description" || prop == "og:description" {
						description = content
					}
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}
	f(doc)
	return title, description, nil
}

