// parseHTML extracts the title and meta description from the HTML content.
func parseHTML(data []byte) (title string, description string) {
	tokenizer := html.NewTokenizer(bytes.NewReader(data))
	isInTitle := false

	for {
		tokenType := tokenizer.Next()
		if tokenType == html.ErrorToken {
			break
		}

		token := tokenizer.Token()

		switch tokenType {
		case html.StartTagToken:
			if token.Data == "title" {
				isInTitle = true
			} else if token.Data == "meta" {
				// Check for meta description
				var isDesc, hasContent bool
				var contentVal string
				for _, attr := range token.Attr {
					key := strings.ToLower(attr.Key)
					val := strings.ToLower(attr.Val)
					if key == "name" && val == "description" {
