					}
					if key == "content" {
						hasContent = true
						contentVal = attr.Val
					}
				}
				if isDesc && hasContent {
					description = contentVal
				}
			}

		case html.TextToken:
			if isInTitle {
				title = token.Data
				isInTitle = false
			}

		case html.EndTagToken:
			if token.Data == "title" {
				isInTitle = false
			}
		}
	}
	return title, description
