// isPrivateHost checks if the host resolves to a private/internal IP.
// It uses a timeout to prevent hanging on slow DNS resolution.
func isPrivateHost(host string) bool {
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	ips, err := net.DefaultResolver.LookupIPAddr(ctx, host)
	if err != nil {
		// If lookup fails, we cannot verify. 
		// Original code allowed proceeding on error, so we return false (not private).
		return false
	}

	for _, ip := range ips {
		if ip.IP.IsLoopback() || ip.IP.IsPrivate() || ip.IP.IsLinkLocalUnicast() {
			return true
		}
	}
	return false
}

