	ReadTimeout:  10 * time.Second,
	WriteTimeout: 10 * time.Second,
	MaxConnDuration: 10 * time.Second,
	// CheckRedirect prevents SSRF attacks via open redirects
	CheckRedirect: func(req *fasthttp.Request, resp *fasthttp.Response) error {
		host := req.URI().Hostname()
		// If the redirect is to a private IP, block it
		if host != "" && isPrivateHost(host) {
			return fmt.Errorf("redirect to private address is not allowed")
		}
		return nil
	},
}

// FetchURLPreview handles POST requests, fetches the URL, and extracts title/description.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// 1. Parse Request Body
	var reqPayload RequestPayload
	if err := json.Unmarshal(ctx.PostBody(), &reqPayload); err != nil {
		ctx.Error("Invalid JSON body", fasthttp.StatusBadRequest)
		return
	}

	// 2. Validate URL
	parsedURL, err := url.ParseRequestURI(reqPayload.URL)
	if err != nil {
		ctx.Error("Invalid URL format", fasthttp.StatusBadRequest)
		return
	}
	if parsedURL.Scheme == "" || parsedURL.Host == "" {
		ctx.Error("Invalid URL: scheme and host are required", fasthttp.StatusBadRequest)
		return
	}

	// 2.1. SSRF Protection: Validate that the host is not a private/internal IP
	host := parsedURL.Hostname()
	if host == "" {
		ctx.Error("Invalid URL: missing hostname", fasthttp.StatusBadRequest)
		return
	}

	// Check the initial URL host
	if isPrivateHost(host) {
		ctx.Error("Access to private/internal addresses is not allowed", fasthttp.StatusBadRequest)
		return
	}

	// 3. Prepare fasthttp Request
	req := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(req)
	req.SetRequestURI(reqPayload.URL)
	req.Header.SetMethod("GET")

	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(resp)

	// Requirement: MUST use fasthttp.Client.DoRedirects method
	// We allow up to 10 redirects.
	if err := client.DoRedirects(req, resp, 10); err != nil {
		ctx.Error(fmt.Sprintf("Failed to fetch URL: %s", err.Error()), fasthttp.StatusBadGateway)
		return
	}

	// Check HTTP Status
	if resp.StatusCode() != fasthttp.StatusOK {
		ctx.Error(fmt.Sprintf("Target URL returned status: %d", resp.StatusCode()), fasthttp.StatusBadGateway)
		return
	}

	// 4. Parse HTML to extract Title and Meta Description
	bodyBytes := resp.Body()
	doc, err := html.Parse(bytes.NewReader(bodyBytes))
	if err != nil {
		ctx.Error(fmt.Sprintf("Failed to parse HTML: %s", err.Error()), fasthttp.StatusInternalServerError)
		return
	}

	var title, description string

	// Recursive function to traverse the DOM tree
	var traverse func(*html.Node)
	traverse = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract Title
			if n.Data == "title" && n.FirstChild != nil {
				title = n.FirstChild.Data
			}
			// Extract Meta Description
			if n.Data == "meta" {
				var isDescription bool
				var content string
				for _, attr := range n.Attr {
					if attr.Key == "name" && attr.Val == "description" {
						isDescription = true
					}
					if attr.Key == "content" {
						content = attr.Val
					}
				}
				if isDescription {
					description = content
				}
			}
		}
		// Continue traversing children
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			traverse(c)
		}
	}
	traverse(doc)

	// 5. Construct and Send JSON Response
	resPayload := ResponsePayload{
		Title:       title,
		Description: description,
	}

	ctx.SetContentType("application/json")
	if err := json.NewEncoder(ctx).Encode(resPayload); err != nil {
		ctx.Error("Failed to encode response", fasthttp.StatusInternalServerError)
	}
}

func main() {
	// Start the server
	if err := fasthttp.ListenAndServe(":8080", FetchURLPreview); err != nil {
		log.Fatalf("Error in ListenAndServe: %s", err)
	}
}

