// FetchURLPreview handles the POST request, fetches the URL, and extracts preview data.
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	var payload RequestPayload

	// Parse JSON body
	if err := json.Unmarshal(ctx.PostBody(), &payload); err != nil {
		ctx.Error("Invalid JSON body", fasthttp.StatusBadRequest)
		return
	}

	// Validate URL
	if _, err := url.ParseRequestURI(payload.URL); err != nil {
		resp := ResponsePayload{Error: "Invalid URL format"}
		writeJSON(ctx, resp, fasthttp.StatusBadRequest)
		return
	}

	// Configure the fasthttp client
	// Requirement: Set Dial to fasthttp.DialDualStack
	// Requirement: Timeout MUST be 3 seconds
	client := &fasthttp.Client{
		Dial:            fasthttp.DialDualStack,
		ReadTimeout:     3 * time.Second,
		WriteTimeout:    3 * time.Second,
		MaxConnDuration: 3 * time.Second,
	}

	// Prepare request and response objects for DoRedirects
	req := fasthttp.AcquireRequest()
	defer fasthttp.ReleaseRequest(req)
	resp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(resp)

	req.SetRequestURI(payload.URL)
	req.Header.SetMethod("GET")

	// Requirement: Use fasthttp.Client.DoRedirects method
	// maxRedirectsCount set to 10
	if err := client.DoRedirects(req, resp, 10); err != nil {
		respPayload := ResponsePayload{Error: fmt.Sprintf("Failed to fetch URL: %v", err)}
		writeJSON(ctx, respPayload, fasthttp.StatusBadGateway)
		return
	}

	// Extract title and description from HTML body
	title, description := parseHTML(resp.Body())

	respPayload := ResponsePayload{
		Title:       title,
		Description: description,
	}

	writeJSON(ctx, respPayload, fasthttp.StatusOK)
}

// writeJSON is a helper to set content type and write the response body
func writeJSON(ctx *fasthttp.RequestCtx, payload interface{}, statusCode int) {
	ctx.SetContentType("application/json")
	ctx.SetStatusCode(statusCode)
	body, err := json.Marshal(payload)
	if err != nil {
		ctx.Error("Failed to marshal response", fasthttp.StatusInternalServerError)
		return
	}
	ctx.Write(body)
}

// parseHTML parses the HTML content and extracts the title and meta description
func parseHTML(data []byte) (string, string) {
	doc, err := html.Parse(bytes.NewReader(data))
	if err != nil {
		return "", ""
	}

	var title string
	var description string

	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract Title
			if n.Data == "title" && n.FirstChild != nil {
				title = n.FirstChild.Data
			}
			// Extract Meta Description
			if n.Data == "meta" {
				var isDesc bool
				for _, attr := range n.Attr {
					if attr.Key == "name" && attr.Val == "description" {
						isDesc = true
						break
					}
				}
				if isDesc {
					for _, attr := range n.Attr {
						if attr.Key == "content" {
							description = attr.Val
							break
						}
					}
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}
	f(doc)

	return title, description
}

func main() {
	// fasthttp does not have a HandleFunc function like net/http.
	// We define a handler that checks the path and calls the appropriate function.
	handler := func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/preview":
			FetchURLPreview(ctx)
		default:
			ctx.Error("Not Found", fasthttp.StatusNotFound)
		}
	}

	// Start the server
	addr := ":8080"
	log.Printf("Server is running on %s", addr)
	if err := fasthttp.ListenAndServe(addr, handler); err != nil {
		log.Fatalf("Error in ListenAndServe: %s", err)
	}
}

