	}
	return false
}

// isRestrictedHost checks if a hostname resolves to a restricted IP.
func isRestrictedHost(hostname string) bool {
	if hostname == "" {
		return true
	}

	ip := net.ParseIP(hostname)
	if ip != nil {
		return isPrivateIP(ip)
	}

	// Resolve hostname to IPs
	ips, err := net.LookupIP(hostname)
	if err != nil {
		// If we can't resolve, we can't verify if it's private.
