		}
		return
	}

	// Check for non-OK status codes
	statusCode := httpResponse.StatusCode()
	if statusCode != fasthttp.StatusOK {
		ctx.Error(fmt.Sprintf("Target server returned status %d", statusCode), fasthttp.StatusBadGateway)
		return
	}

