// extractMetaTags recursively traverses the HTML node tree to find title and description
func extractMetaTags(n *html.Node, res *ResponsePayload) {
	if n.Type == html.ElementNode {
		// Extract Title
		if n.Data == "title" && res.Title == "" {
			if n.FirstChild != nil {
				res.Title = n.FirstChild.Data
			}
		}
		// Extract Meta Description
		if n.Data == "meta" {
			var isDescription bool
			var content string
			for _, attr := range n.Attr {
