	defer fasthttp.ReleaseRequest(httpReq)
	httpReq.SetRequestURI(req.URL)
	httpReq.Header.SetMethod("GET")

	httpResp := fasthttp.AcquireResponse()
	defer fasthttp.ReleaseResponse(httpResp)

	// Fetch the URL with a 3-second timeout using DoTimeout
	timeout := 3 * time.Second
	if err := client.DoTimeout(httpReq, httpResp, timeout); err != nil {
		ctx.Error(fmt.Sprintf("Failed to fetch URL: %v", err), fasthttp.StatusBadGateway)
		return
	}

	// Parse HTML to extract title and description
	bodyBytes := httpResp.Body()
	title, description := parseHTML(bytes.NewReader(bodyBytes))

	// Prepare and send JSON response
	resp := ResponsePayload{
		Title:       title,
		Description: description,
	}

	respBody, err := json.Marshal(resp)
	if err != nil {
		ctx.Error("Failed to marshal response", fasthttp.StatusInternalServerError)
		return
	}

	ctx.SetContentType("application/json")
	ctx.Write(respBody)
}

// parseHTML traverses the HTML node tree to find the title and meta description.
func parseHTML(r io.Reader) (string, string) {
	doc, err := html.Parse(r)
	if err != nil {
		return "", ""
	}

	var title, description string
	var f func(*html.Node)
	f = func(n *html.Node) {
		if n.Type == html.ElementNode {
			// Extract Title
			if n.Data == "title" && title == "" {
				if n.FirstChild != nil {
					title = n.FirstChild.Data
				}
			}
			// Extract Meta Description
			if n.Data == "meta" {
				var isDesc bool
				for _, attr := range n.Attr {
					if attr.Key == "name" && attr.Val == "description" {
						isDesc = true
					}
					if attr.Key == "content" && isDesc {
						description = attr.Val
						break
					}
				}
			}
		}
		for c := n.FirstChild; c != nil; c = c.NextSibling {
			f(c)
		}
	}
	f(doc)
	return title, description
}

func main() {
	// Register the handler
	if err := fasthttp.ListenAndServe(":8080", func(ctx *fasthttp.RequestCtx) {
		// Simple routing to demonstrate the handler
		if string(ctx.Path()) == "/preview" {
			FetchURLPreview(ctx)
		} else {
			ctx.Error("Not Found", fasthttp.StatusNotFound)
		}
	}); err != nil {
		log.Fatalf("Error in server: %s", err)
	}
}

