// isSafeURL validates the URL to prevent SSRF
func isSafeURL(rawURL string) bool {
	parsedURL, err := url.Parse(rawURL)
	if err != nil {
		return false
	}

	host := parsedURL.Hostname()
	if host == "" {
		return false
	}

	// Restrict to http and https
	if parsedURL.Scheme != "http" && parsedURL.Scheme != "https" {
		return false
	}

	// Check if host is a direct IP
	ip := net.ParseIP(host)
	if ip != nil {
		return !isPrivateIP(ip)
	}

	// If not a direct IP, resolve hostname to check against internal IPs
	// Use a timeout for DNS lookup to prevent hanging
	ctx, cancel := context.WithTimeout(context.Background(), 2*time.Second)
	defer cancel()

	resolver := &net.Resolver{}
	ips, err := resolver.LookupIPAddr(ctx, host)
	if err != nil {
