)

// RequestPayload defines the JSON structure for the incoming request
type RequestPayload struct {
	URL string `json:"url"`
}

// ResponsePayload defines the JSON structure for the response
type ResponsePayload struct {
	Title       string `json:"title"`
	Description string `json:"description"`
}

var (
	// client is the fasthttp client used to fetch URLs
	client = &fasthttp.Client{
		Dial:               fasthttp.DialDualStack,
		ReadTimeout:        3 * time.Second,
		WriteTimeout:       3 * time.Second,
		MaxConnDuration:    3 * time.Second,
		DisableHeaderNamesNormalizing: true,
	}
)

// FetchURLPreview handles the POST request, fetches the URL, and extracts metadata
func FetchURLPreview(ctx *fasthttp.RequestCtx) {
	// 1. Parse the JSON body
	var reqPayload RequestPayload
	if err := json.Unmarshal(ctx.PostBody(), &reqPayload); err != nil {
		ctx.Error("Invalid JSON body", fasthttp.StatusBadRequest)
		return
	}

	if reqPayload.URL == "" {
		ctx.Error("URL field is required", fasthttp.StatusBadRequest)
		return
	}

	// 2. Prepare the HTTP request
	var req fasthttp.Request
	var resp fasthttp.Response

	req.SetRequestURI(reqPayload.URL)
	req.Header.SetMethod("GET")
	// Set a User-Agent to avoid being blocked by basic bot filters
	req.Header.SetUserAgent("Mozilla/5.0 (compatible; URLPreviewBot/1.0; +https://example.com/bot)")

	// 3. Fetch the URL using DoRedirects
	// DoRedirects automatically follows redirects (up to a limit)
	err := client.DoRedirects(&req, &resp, 10)
	if err != nil {
		log.Printf("Error fetching URL %s: %v", reqPayload.URL, err)
		ctx.Error("Failed to fetch URL", fasthttp.StatusBadGateway)
		return
	}

	// 4. Check status code
	statusCode := resp.StatusCode()
	if statusCode != fasthttp.StatusOK {
		ctx.Error("Unexpected status code from target URL", fasthttp.StatusBadGateway)
		return
	}

	// 5. Parse HTML content
	bodyBytes := resp.Body()
	doc, err := goquery.NewDocumentFromReader(bytes.NewReader(bodyBytes))
	if err != nil {
		log.Printf("Error parsing HTML from %s: %v", reqPayload.URL, err)
		ctx.Error("Failed to parse HTML content", fasthttp.StatusInternalServerError)
		return
	}

	// 6. Extract Title and Description
	result := ResponsePayload{
		Title:       doc.Find("title").Text(),
		Description: "",
	}

	// Look for meta description with name="description"
	if selection, exists := doc.Find("meta[name='description']").Attr("content"); exists {
		result.Description = selection
	} else if selection, exists := doc.Find("meta[property='og:description']").Attr("content"); exists {
		// Fallback to Open Graph description if standard description is missing
		result.Description = selection
	}

	// 7. Return JSON response
	ctx.SetContentType("application/json")
	respBody, err := json.Marshal(result)
	if err != nil {
		ctx.Error("Failed to marshal response", fasthttp.StatusInternalServerError)
		return
	}

	ctx.Write(respBody)
}

func main() {
	// Register the handler
	// Note: In a real application, you might want to wrap this with middleware for logging, recovery, etc.
	handler := func(ctx *fasthttp.RequestCtx) {
		switch string(ctx.Path()) {
		case "/preview":
			FetchURLPreview(ctx)
		default:
			ctx.Error("Not Found", fasthttp.StatusNotFound)
		}
	}

	// Start the server
	addr := ":8080"
	log.Printf("Starting server on %s", addr)
	if err := fasthttp.ListenAndServe(addr, handler); err != nil {
		log.Fatalf("Error in ListenAndServe: %v", err)
	}
}

